import numpy as np
import forward

DIM = 10
MAX_NEURONS = 20
OUT_PATH = "/app/stolen_A1.npy"


def f(x):
    return forward.forward(x)


def grad(x, eps=1e-6):
    x = np.asarray(x, dtype=float).reshape(-1)
    g = np.zeros(DIM)
    for i in range(DIM):
        e = np.zeros(DIM)
        e[i] = eps
        g[i] = (f(x + e) - f(x - e)) / (2.0 * eps)
    return g


def refine_kink(x0, d, t_lo, t_hi, iters=60):
    for _ in range(iters):
        t_mid = 0.5 * (t_lo + t_hi)
        dt = max(1e-12, abs(t_hi - t_lo) * 1e-3)
        s_left = (f(x0 + t_mid * d) - f(x0 + (t_mid - dt) * d)) / dt
        s_right = (f(x0 + (t_mid + dt) * d) - f(x0 + t_mid * d)) / dt
        if abs(s_right - s_left) <= 1e-13:
            return t_mid
        t_q = 0.5 * (t_mid + t_hi)
        s_right_far = (f(x0 + (t_q + dt) * d) - f(x0 + (t_q - dt) * d)) / (2 * dt)
        if abs(s_right_far - s_right) > 1e-13:
            t_lo = t_mid
        else:
            t_hi = t_mid
    return 0.5 * (t_lo + t_hi)


def gradient_jump(x0, d, t_kink, margin):
    p_left = x0 + (t_kink - margin) * d
    p_right = x0 + (t_kink + margin) * d
    return grad(p_right) - grad(p_left)


def normalized(v):
    n = np.linalg.norm(v)
    if n < 1e-15:
        return v
    return v / n


def have_vec(v, vecs, tol=1e-3):
    vn = normalized(v)
    for w in vecs:
        wn = normalized(w)
        if abs(abs(np.dot(vn, wn)) - 1.0) < tol:
            return True
    return False


def scan_line(seed):
    rng = np.random.default_rng(seed)
    x0 = rng.normal(0, 0.3, size=DIM)
    d = rng.normal(0, 1, size=DIM)
    d = d / np.linalg.norm(d)

    t_range = 6.0
    n_points = 4000
    ts = np.linspace(-t_range, t_range, n_points)
    vals = np.array([f(x0 + t * d) for t in ts], dtype=float)
    dt = ts[1] - ts[0]

    slopes = np.diff(vals) / dt
    changes = np.abs(np.diff(slopes))
    thresh = max(1e-9, changes.max() * 1e-6)
    idxs = np.where(changes > thresh)[0]

    groups = []
    for idx in idxs:
        if groups and idx <= groups[-1][-1] + 1:
            groups[-1].append(idx)
        else:
            groups.append([idx])

    candidates = []
    for grp in groups:
        a = max(0, min(len(ts) - 2, int(np.median(grp))))
        b = min(len(ts) - 1, a + 1)
        t_kink = refine_kink(x0, d, ts[a], ts[b])
        margin = max(1e-3, 0.05 * dt)
        jump = gradient_jump(x0, d, t_kink, margin)
        if np.linalg.norm(jump) > 1e-8:
            candidates.append(jump)
    return candidates


def main():
    recovered = []
    seed = 0
    max_seeds = 1000

    while len(recovered) < MAX_NEURONS and seed < max_seeds:
        candidates = scan_line(seed)
        seed += 1
        for vec in candidates:
            if not have_vec(vec, recovered, tol=2e-3):
                recovered.append(vec)
        print(f"line {seed}: candidates={len(candidates)} unique={len(recovered)}")
        if len(recovered) >= MAX_NEURONS:
            break

    if len(recovered) < MAX_NEURONS:
        print(f"Warning: recovered only {len(recovered)} rows")
    else:
        recovered = recovered[:MAX_NEURONS]

    A1_stolen = np.vstack(recovered)
    np.save(OUT_PATH, A1_stolen)
    print(f"Saved shape {A1_stolen.shape} to {OUT_PATH}")


if __name__ == "__main__":
    main()
PY
